'use client';
import { Button } from "@/components/ui/button"
import { Dropzone, DropzoneContent, DropzoneEmptyState } from '@/components/ui/shadcn-io/dropzone';
import { useState } from 'react';

export default function Home() {
  const [contextFiles, setContextFiles] = useState<File[] | undefined>();
  const [templateFile, setTemplateFile] = useState<File | undefined>();
  const [success, setSuccess] = useState<Boolean>();

  const handleContextDrop = (contextFiles: File[]) => {
    console.log(contextFiles);
    if (contextFiles) {
      setContextFiles(contextFiles);
    }
  };

  const handleTemplateDrop = (templateFile: File[]) => {
    console.log(templateFile);
    if (templateFile) {
      setTemplateFile(templateFile[0]);
    }
  };

  const uploadFiles = async () => {
    const formData = new FormData();
    if (contextFiles) {
      contextFiles.forEach((file) => formData.append("contextFiles", file))
      }
    if (templateFile) {
      formData.append("templateFile", templateFile)
    }
    const response = await fetch('http://localhost/api/upload', {
        method: 'POST',
        body: formData
      });
    if (response.ok) {
      setSuccess(true);
    }
  }

  return (
      <div className='mx-auto px-10 text-center'>
      <h1 className='text-2xl py-6'>Upload Context</h1>
        <Dropzone
      maxFiles={3}
      onDrop={handleContextDrop}
      onError={console.error}
      src={contextFiles}
      className='border-2 border-black bg-sky-50'
    >
      <DropzoneEmptyState />
      <DropzoneContent />
    </Dropzone>

      <h1 className='text-2xl py-6'>Upload Template</h1>
        <Dropzone
      onDrop={handleTemplateDrop}
      onError={console.error}
      src={templateFile ? [templateFile] : []}
      className='border-2 border-black bg-amber-50'
    >
      <DropzoneEmptyState />
      <DropzoneContent />
    </Dropzone>

    <Button variant="outline" className='py-6 m-6 border-2 border-black w-xl' onClick={uploadFiles}>Submit</Button>
    {success && (
      <div className='p-5 bg-green text-2xl'>
          Success!
      </div>
    )}
        </div>
  );
}
